//! Rust-side Gröbner basis validation: normal-form reduction and
//! Buchberger's criterion check.
//!
//! ark-gb's [`compute_gb`](crate::bba::compute_gb) returns the reduced
//! Gröbner basis of the input ideal, but the upstream rustgb test
//! suite validated correctness by byte-comparing against precomputed
//! Singular reference output. After porting to `ark_ff::Field` the
//! reference output (over `Z/32003`) is no longer applicable, so we
//! validate via **Buchberger's theorem** instead:
//!
//! > A polynomial set `G` is a Gröbner basis of the ideal generated by
//! > input `I` iff
//! > 1. every `f ∈ I` reduces to `0` modulo `G`, AND
//! > 2. for every pair `(g_i, g_j) ∈ G²` with `i < j`, the
//! >    S-polynomial `S(g_i, g_j)` reduces to `0` modulo `G`.
//!
//! Both are checkable purely inside ark-gb using the same
//! reduction infrastructure that drives Buchberger's algorithm itself
//! ([`SBasis`](crate::sbasis::SBasis),
//! [`LObject`](crate::lobject::LObject),
//! [`bba::reduce_lobject_geobucket`](crate::bba::reduce_lobject_geobucket)).
//!
//! ## Caveats
//!
//! Because [`is_groebner_basis`] reuses the same reducer that
//! [`compute_gb`](crate::bba::compute_gb) uses internally, a bug in
//! the reducer could let a wrong GB validate as correct. Pair this
//! validator with hand-checkable closed-form sanity tests (see
//! `tests/gb_sanity.rs`) for full coverage.

use std::sync::Arc;

use crate::bba::reduce_lobject_geobucket;
use crate::field::Field;
use crate::lobject::LObject;
use crate::pair::Pair;
use crate::poly::Poly;
use crate::ring::Ring;
use crate::sbasis::SBasis;

/// Failure mode reported by [`is_groebner_basis`].
#[derive(Debug)]
pub enum GbError<F: Field + Copy + Send + Sync + 'static> {
    /// Input generator at index `idx` did not reduce to zero modulo
    /// the candidate GB. The non-zero residue is included for
    /// diagnostics.
    InputNotInIdeal {
        /// Index of the offending input polynomial.
        idx: usize,
        /// The non-zero residue of `inputs[idx]` after reduction.
        residue: Poly<F>,
    },
    /// The S-polynomial of `(gb[i], gb[j])` (with `i < j`) did not
    /// reduce to zero modulo the candidate GB.
    SPolyNotZero {
        /// First index in the offending pair.
        i: usize,
        /// Second index in the offending pair.
        j: usize,
        /// The non-zero residue of `S(gb[i], gb[j])` after reduction.
        residue: Poly<F>,
    },
}

/// Build an [`SBasis`] from an already-reduced GB. The basis is
/// inserted in input order; each insert triggers
/// [`SBasis::clear_redundant_for`], which is a no-op for a properly
/// reduced GB but keeps the contract the reducer relies on.
fn build_sbasis<F: Field + Copy + Send + Sync + 'static>(
    ring: &Ring<F>,
    basis: &[Poly<F>],
) -> SBasis<F> {
    let mut sb = SBasis::new();
    for p in basis {
        if p.is_zero() {
            continue;
        }
        // Make monic so the reducer's `s_lc.is_one()` debug-assert
        // holds even if the caller hands us a non-monic basis.
        let Some(monic_p) = p.monic(ring) else {
            continue;
        };
        sb.insert(ring, monic_p);
    }
    sb
}

/// Reduce `f` to its normal form modulo `basis` under the ring's
/// monomial order.
///
/// The basis is treated as a set of generators and is internally
/// re-wrapped in an [`SBasis`]; pass the output of
/// [`compute_gb`](crate::bba::compute_gb) directly.
pub fn normal_form<F: Field + Copy + Send + Sync + 'static>(
    ring: &Arc<Ring<F>>,
    f: &Poly<F>,
    basis: &[Poly<F>],
) -> Poly<F> {
    if f.is_zero() {
        return f.clone();
    }
    let s_basis = build_sbasis(ring, basis);
    let mut lobj = LObject::from_poly(Arc::clone(ring), f.clone());
    reduce_lobject_geobucket(&mut lobj, &s_basis, ring);
    lobj.into_poly()
}

/// Verify Buchberger's criterion on `(input, gb)`.
///
/// Returns `Ok(())` if `gb` is a Gröbner basis of the ideal
/// `⟨input⟩`. Otherwise returns the **first** failure encountered:
/// either an input generator that doesn't reduce to zero
/// ([`GbError::InputNotInIdeal`]) or an S-polynomial of a pair in
/// `gb` that doesn't reduce to zero ([`GbError::SPolyNotZero`]).
///
/// Cost: `O(|input| · NF + |gb|² · NF)` where `NF` is one
/// normal-form reduction. For `|gb|` in the tens to hundreds and
/// release-mode reductions, this is the right shape for a
/// regression check.
pub fn is_groebner_basis<F: Field + Copy + Send + Sync + 'static>(
    ring: &Arc<Ring<F>>,
    input: &[Poly<F>],
    gb: &[Poly<F>],
) -> Result<(), GbError<F>> {
    let s_basis = build_sbasis(ring, gb);

    // (1) input ⊆ ⟨gb⟩.
    for (idx, f) in input.iter().enumerate() {
        if f.is_zero() {
            continue;
        }
        let mut lobj = LObject::from_poly(Arc::clone(ring), f.clone());
        reduce_lobject_geobucket(&mut lobj, &s_basis, ring);
        if !lobj.is_zero() {
            return Err(GbError::InputNotInIdeal {
                idx,
                residue: lobj.into_poly(),
            });
        }
    }

    // (2) Every S-polynomial of pairs in gb reduces to 0 mod gb.
    // We re-fetch leading monomials via the SBasis's poly() rather
    // than the original `gb` slice, because build_sbasis re-monics
    // the inputs.
    //
    // Buchberger's First Criterion (a.k.a. the "product" /
    // "coprime LM" criterion): if `gcd(LM(g_i), LM(g_j)) == 1` then
    // `S(g_i, g_j)` reduces to 0 modulo `{g_i, g_j}` and a fortiori
    // modulo `G`. We detect coprimality in O(1) via the cached short
    // exponent vector — with `nvars <= 31` each variable owns a
    // unique SEV bit (see MonoTerm::div, line 347), so
    // `(sev_i & sev_j) == 0` is exactly "no shared variable" =
    // coprime LMs. This is sound for validation (it is one of
    // Buchberger's two original criteria, proven independent of any
    // ordering or reducer choice) and is the dominant cost saver on
    // sparse ideals like Cyclic-N.
    let n = s_basis.len();
    for i in 0..n {
        if s_basis.is_redundant(i) {
            continue;
        }
        let s_i = s_basis.poly(i);
        let lm_i = s_i.leading().expect("non-zero basis element").1;
        let sev_i = lm_i.sev();
        for j in (i + 1)..n {
            if s_basis.is_redundant(j) {
                continue;
            }
            let s_j = s_basis.poly(j);
            let lm_j = s_j.leading().expect("non-zero basis element").1;
            // Coprime-LM fast-path: skip the whole reduction.
            if (sev_i & lm_j.sev()) == 0 {
                continue;
            }
            // Build a placeholder Pair carrying the lcm of the two
            // leading monomials; sugar/arrival are not consulted by
            // the reduction path.
            let lcm = lm_i.lcm(lm_j, ring);
            let pair = Pair::new(i as u32, j as u32, lcm, 0, 0);
            let mut lobj = match LObject::from_spoly(Arc::clone(ring), s_i, s_j, &pair) {
                Some(o) => o,
                // S-poly trivially zero (e.g. coprime leading terms
                // already cancel); skip.
                None => continue,
            };
            reduce_lobject_geobucket(&mut lobj, &s_basis, ring);
            if !lobj.is_zero() {
                return Err(GbError::SPolyNotZero {
                    i,
                    j,
                    residue: lobj.into_poly(),
                });
            }
        }
    }
    Ok(())
}
